import { Link } from "react-router-dom";

function ProductCard({ product }) {
  return (
    <div className="product-card">
      <h3>{product.name}</h3>
      <p>{product.price} kr</p>

      <Link to={"/products/" + product.id}>
        Se produkt
      </Link>
    </div>
  );
}

export default ProductCard;
